parameters.text:
=Classify this professional into a persona bucket:

Record ID: {{ $json.record_id }}
Full Name: {{ $json.full_name }}
Designation: {{ $json.designation }}
Profile URL: {{ $json.profile_url }}

Return ONLY this exact JSON:
{
  "record_id": "{{ $json.record_id }}",
  "full_name": "{{ $json.full_name }}",
  "designation": "{{ $json.designation }}",
  "persona_bucket": "Technical|Functional|Sales|Leadership",
  "confidence": "High|Medium|Low",
  "rationale": "One sentence explaining why"
}

parameters.jsCode:
const item = $input.first();
const original = $('Loop Over Items').first().json;

// Get AI output
let rawOutput = item.json.output || '';
let classData = {};

try {
  if (typeof rawOutput === 'string') {
    rawOutput = rawOutput
      .replace(/```json/gi, '')
      .replace(/```/g, '')
      .trim();

    const start = rawOutput.indexOf('{');
    const end = rawOutput.lastIndexOf('}');

    if (start !== -1 && end !== -1) {
      classData = JSON.parse(
        rawOutput.substring(start, end + 1)
      );
    }
  } else if (typeof rawOutput === 'object') {
    classData = rawOutput;
  }
} catch(e) {
  // Safe fallback
  return [{
    json: {
      record_id: original.record_id,
      full_name: original.full_name,
      designation: original.designation,
      persona_bucket: 'Functional',
      confidence: 'Low',
      rationale: 'Parse failed — default assigned',
      error: true,
      processed_at: new Date().toISOString()
    }
  }];
}

// Valid persona buckets
const validBuckets = [
  'Technical', 'Functional',
  'Sales', 'Leadership'
];

// Normalize persona bucket
let bucket = (classData.persona_bucket || '')
  .trim();
if (!validBuckets.includes(bucket)) {
  // Try to match partial
  const found = validBuckets.find(b =>
    bucket.toLowerCase().includes(b.toLowerCase())
  );
  bucket = found || 'Functional';
}

// Normalize confidence
const validConf = ['High', 'Medium', 'Low'];
let confidence = (classData.confidence || 'Medium')
  .trim();
if (!validConf.includes(confidence)) {
  confidence = 'Medium';
}

// Normalize profile URL
let profileUrl = (original.profile_url || '').trim();
if (profileUrl && !profileUrl.startsWith('https://')) {
  profileUrl = 'https://' + profileUrl;
}
if (profileUrl && !profileUrl.endsWith('/')) {
  profileUrl = profileUrl + '/';
}

// Normalize name title case
const fullName = (
  classData.full_name ||
  original.full_name || ''
).trim()
  .split(' ')
  .map(w => w.charAt(0).toUpperCase() +
             w.slice(1).toLowerCase())
  .join(' ');

// Normalize designation
const designation = (
  classData.designation ||
  original.designation || ''
).trim();

return [{
  json: {
    record_id: original.record_id,
    full_name: fullName,
    designation: designation,
    profile_url: profileUrl,
    persona_bucket: bucket,
    confidence: confidence,
    rationale: (classData.rationale || '')
                .substring(0, 300),
    error: false,
    processed_at: new Date().toISOString()
  }
}];
